<template>
  <view v-if="visible" class="loading-mask" :class="{ 'mask-blur': blur }" @tap="onMaskTap">
    <view class="loading-box" @tap.stop>
      <!-- 自定义 logo：优先用图片 -->
      <view v-if="logo" class="logo-wrap">
        <image
          class="logo-img"
          :class="{ 'logo-spin': logoSpin }"
          :src="logo"
          mode="aspectFit"
        />
      </view>
      <!-- 内置样式：无 logo 时显示 -->
      <view v-else class="builtin-wrap">
        <view v-if="styleType === 'spinner'" class="spinner"></view>
        <view v-else-if="styleType === 'dots'" class="dots">
          <view class="dot"></view>
          <view class="dot"></view>
          <view class="dot"></view>
        </view>
        <view v-else class="tea-steam">
          <view class="cup">🍵</view>
          <view class="steam s1"></view>
          <view class="steam s2"></view>
          <view class="steam s3"></view>
        </view>
      </view>
      <text v-if="title" class="loading-title">{{ title }}</text>
    </view>
  </view>
</template>

<script>
export default {
  name: 'LoadingMask',
  props: {
    // 是否显示
    visible: {
      type: Boolean,
      default: false
    },
    // 提示文字
    title: {
      type: String,
      default: '加载中...'
    },
    // 自定义 logo 图片地址（设置后优先显示图片）
    logo: {
      type: String,
      default: ''
    },
    // logo 是否旋转
    logoSpin: {
      type: Boolean,
      default: true
    },
    // 内置样式类型：'spinner' | 'dots' | 'tea'
    styleType: {
      type: String,
      default: 'tea'
    },
    // 是否背景模糊
    blur: {
      type: Boolean,
      default: true
    },
    // 点击遮罩是否关闭（一般 loading 不关闭，按需开启）
    maskClosable: {
      type: Boolean,
      default: false
    }
  },
  emits: ['maskTap'],
  setup(props, { emit }) {
    const onMaskTap = () => {
      if (props.maskClosable) emit('maskTap')
    }
    return { onMaskTap }
  }
}
</script>

<style lang="scss" scoped>
.loading-mask {
  position: fixed;
  left: 0;
  right: 0;
  top: 0;
  bottom: 0;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: rgba(0, 0, 0, 0.4);
  &.mask-blur {
    backdrop-filter: blur(8rpx);
  }
}

.loading-box {
  min-width: 200rpx;
  padding: 40rpx 48rpx;
  background: rgba(255, 255, 255, 0.95);
  border-radius: 24rpx;
  display: flex;
  flex-direction: column;
  align-items: center;
  box-shadow: 0 16rpx 48rpx rgba(0, 0, 0, 0.12);
}

.logo-wrap {
  width: 100rpx;
  height: 100rpx;
  margin-bottom: 24rpx;
}
.logo-img {
  width: 100%;
  height: 100%;
  &.logo-spin {
    animation: spin 1s linear infinite;
  }
}

/* 内置：转圈 */
.spinner {
  width: 72rpx;
  height: 72rpx;
  margin-bottom: 24rpx;
  border: 6rpx solid #e5e5e5;
  border-top-color: #023993;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

/* 内置：三点跳动 */
.dots {
  display: flex;
  gap: 16rpx;
  margin-bottom: 24rpx;
  .dot {
    width: 16rpx;
    height: 16rpx;
    border-radius: 50%;
    background: #023993;
    animation: bounce 0.6s ease-in-out infinite;
    &:nth-child(2) { animation-delay: 0.1s; }
    &:nth-child(3) { animation-delay: 0.2s; }
  }
}

/* 内置：茶杯热气 */
.tea-steam {
  position: relative;
  margin-bottom: 24rpx;
  .cup {
    font-size: 64rpx;
    line-height: 1;
  }
  .steam {
    position: absolute;
    bottom: 56rpx;
    width: 8rpx;
    height: 24rpx;
    background: linear-gradient(to top, rgba(0,0,0,0.15), transparent);
    border-radius: 4rpx;
    animation: steam 1.2s ease-in-out infinite;
  }
  .s1 { left: 50%; transform: translateX(-120%); animation-delay: 0s; }
  .s2 { left: 50%; transform: translateX(-50%); animation-delay: 0.2s; }
  .s3 { left: 50%; transform: translateX(20%);  animation-delay: 0.4s; }
}

.loading-title {
  font-size: 28rpx;
  color: #666;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-12rpx); }
}
@keyframes steam {
  0%, 100% { opacity: 0.3; transform: translateY(0) scaleY(1); }
  50% { opacity: 0.8; transform: translateY(-8rpx) scaleY(1.2); }
}
</style>
